#!/usr/bin/env node
// Rename and move batch outputs from nh-outputs/ into Noble Harbor Wholesale/<Peptide>/v2/.
// Matches each job to its output by parsing the slug tag in the filename — works
// even when the batch was generated by multiple parallel workers (so chronological
// order does not necessarily match the job index).
//
// Usage: node nh-rename-batch.mjs <batch.json>
//   The batch JSON must have _meta {peptide, size, color, tag} for each job.
//
// Output path: Noble Harbor Wholesale/<Peptide>/v2/<Peptide_underscored>_<size>_<color>.jpg

import fs from "fs";
import path from "path";

const batchFile = process.argv[2];
if (!batchFile) {
  console.error("Usage: node nh-rename-batch.mjs <batch.json>");
  process.exit(1);
}

const jobs = JSON.parse(fs.readFileSync(batchFile, "utf8"));

const GENS = process.env.OUTPUT_DIR || "nh-outputs";
if (!fs.existsSync(GENS)) {
  console.error(`Output directory not found: ${GENS}`);
  process.exit(1);
}

const allGens = fs.readdirSync(GENS).filter(f => /\.(jpg|png)$/i.test(f));

// Slug used by nanobanana.mjs: first 40 chars of prompt, [^a-zA-Z0-9]+ → "_".
// Each job's prompt starts with "<tag>: Pharmaceutical vial..." so the slug always begins
// with the tag, with hyphens turned into underscores.
const tagToSlug = (tag) => tag.replace(/-/g, "_");

console.log(`Batch jobs: ${jobs.length}`);
console.log(`Output candidates in ${GENS}: ${allGens.length}`);

const peptideUnderscore = (name) => name.replace(/\s+/g, "_");

let moved = 0;
let skipped = 0;
let collisions = 0;
const usedFiles = new Set();

for (const job of jobs) {
  const meta = job._meta;
  if (!meta) { skipped++; continue; }

  const slugTag = tagToSlug(meta.tag);
  // The slug in the filename may be truncated (nanobanana.mjs caps it at 40 chars), so
  // we match the longest prefix that fits — and accept either an underscore or "." (file
  // extension) directly after the slug, since truncation can land anywhere.
  const truncated = slugTag.slice(0, 40);
  const re = new RegExp(`_${truncated.replace(/[-.]/g, "\\$&")}(_|\\.)`);
  const matches = allGens.filter(f => re.test(f) && !usedFiles.has(f));
  if (matches.length === 0) {
    console.warn(`  ${meta.tag}: no matching output file in ${GENS}`);
    skipped++;
    continue;
  }
  if (matches.length > 1) collisions++;
  // Take the most recent if multiple matches (re-runs / retries)
  matches.sort();
  const match = matches[matches.length - 1];
  usedFiles.add(match);

  const peptideFolder = path.join("Noble Harbor Wholesale", meta.peptide, "v2");
  fs.mkdirSync(peptideFolder, { recursive: true });
  const ext = path.extname(match);
  const newName = `${peptideUnderscore(meta.peptide)}_${meta.size}_${meta.color}${ext}`;
  const dst = path.join(peptideFolder, newName);
  fs.renameSync(path.join(GENS, match), dst);
  moved++;
  if (moved <= 3 || moved === jobs.length) {
    console.log(`  ${meta.tag} → ${dst}`);
  } else if (moved === 4) {
    console.log(`  …`);
  }
}

console.log(`\nDone: ${moved} moved, ${skipped} skipped, ${collisions} multi-match (latest used).`);
